import { put } from 'redux-saga/effects';
import { AxiosResponse } from 'axios';

import { Navigation } from 'services';
import { ROUTES } from 'router';
import { LoginUserActionStart, userActions } from 'store/reducers/user';
import { globalActions } from 'store/reducers/global';

import { User, UserController } from 'controllers';

export function* AuthenticationSaga(action: LoginUserActionStart) {
  const { discordCode } = action;

  try {
    const response: AxiosResponse<User> = yield UserController.loginUser(discordCode);

    yield put(userActions.loginUserSuccess(response));
  } catch (error) {
    // Process unknown or internal server errors
    if (!error.response || error.response.status >= 500) {
      yield put(globalActions.setUnexpectedError(error));
      return;
    }

    yield put(userActions.loginUserFailure(error));
    yield put(userActions.userNotAuthorized());
  } finally {
    Navigation.goTo(ROUTES.Public.Home);
  }
}
