import { RootAction } from 'store';

import { ChallengesActionTypes, ChallengesState as State } from './types';

const initialState: State = {
  list: undefined,
};

export const challengesReducer = (state: State = initialState, action: RootAction): State => {
  switch (action.type) {
    case ChallengesActionTypes.FETCH_CHALLENGES_SUCCESS:
      return { ...state, list: action.payload.data.challenges };

    default:
      return state;
  }
};
