import { AxiosError, AxiosResponse } from 'axios';

import { ApiFailureAction, ApiStartAction, ApiSuccessAction } from 'types';
import { Challenge, FetchChallengesResponse } from 'controllers';

export type ChallengesState = {
  list?: Challenge[];
};

export enum ChallengesActionTypes {
  FETCH_CHALLENGES_START = 'challenges|fetchChallenges:start',
  FETCH_CHALLENGES_SUCCESS = 'challenges|fetchChallenges:success',
  FETCH_CHALLENGES_FAILURE = 'challenges|fetchChallenges:failure',
}

//<editor-fold desc="Fetch challenges">
export interface FetchChallengesActionStart extends ApiStartAction {
  type: ChallengesActionTypes.FETCH_CHALLENGES_START;
  followupActions: {
    SUCCESS: (response: AxiosResponse<FetchChallengesResponse>) => FetchChallengesActionSuccess;
    FAILURE: (error: AxiosError) => FetchChallengesActionFailure;
  };
}

export interface FetchChallengesActionSuccess extends ApiSuccessAction {
  type: ChallengesActionTypes.FETCH_CHALLENGES_SUCCESS;
  payload: AxiosResponse<FetchChallengesResponse>;
}

export interface FetchChallengesActionFailure extends ApiFailureAction {
  type: ChallengesActionTypes.FETCH_CHALLENGES_FAILURE;
}
//</editor-fold>

//<editor-fold desc="Export action typings">
export type ChallengesActions =
  | FetchChallengesActionStart
  | FetchChallengesActionSuccess
  | FetchChallengesActionFailure;
//</editor-fold>
