import { AxiosError, AxiosResponse } from 'axios';
import { AnyAction } from 'redux';

import { ApiFailureAction, ApiStartAction, ApiSuccessAction } from 'types';
import { FetchUserInfoResponse, LoginUserResponse, LogoutUserResponse, User } from 'controllers';

export type UserState = {
  userInfo?: User | null;
};

export enum UserActionTypes {
  FETCH_USER_INFO__START = 'user|fetchUserInfo:start',
  FETCH_USER_INFO__SUCCESS = 'user|fetchUserInfo:success',
  FETCH_USER_INFO__FAILURE = 'user|fetchUserInfo:failure',

  LOGIN_USER__START = 'user|loginUser:start',
  LOGIN_USER__SUCCESS = 'user|loginUser:success',
  LOGIN_USER__FAILURE = 'user|loginUser:failure',

  LOGOUT_USER__START = 'user|logoutUser:start',
  LOGOUT_USER__SUCCESS = 'user|logoutUser:success',
  LOGOUT_USER__FAILURE = 'user|logoutUser:failure',

  USER_NOT_AUTHORIZED = 'user|userNotAuthorized',
}

//<editor-fold desc="Fetch user info">
export interface FetchUserInfoActionStart extends ApiStartAction {
  type: UserActionTypes.FETCH_USER_INFO__START;
  followupActions: {
    SUCCESS: (response: AxiosResponse<FetchUserInfoResponse>) => FetchUserInfoActionSuccess;
    FAILURE: (error: AxiosError) => FetchUserInfoActionFailure;
  };
}

export interface FetchUserInfoActionSuccess extends ApiSuccessAction {
  type: UserActionTypes.FETCH_USER_INFO__SUCCESS;
  payload: AxiosResponse<FetchUserInfoResponse>;
}

export interface FetchUserInfoActionFailure extends ApiFailureAction {
  type: UserActionTypes.FETCH_USER_INFO__FAILURE;
}
//</editor-fold>

//<editor-fold desc="Login user">
export interface LoginUserActionStart extends AnyAction {
  type: UserActionTypes.LOGIN_USER__START;
  discordCode: string;
}

export interface LoginUserActionSuccess extends ApiSuccessAction {
  type: UserActionTypes.LOGIN_USER__SUCCESS;
  payload: AxiosResponse<LoginUserResponse>;
}

export interface LoginUserActionFailure extends ApiFailureAction {
  type: UserActionTypes.LOGIN_USER__FAILURE;
}
//</editor-fold>

//<editor-fold desc="Logout user">
export interface LogoutUserActionStart extends ApiStartAction {
  type: UserActionTypes.LOGOUT_USER__START;
  followupActions: {
    SUCCESS: (response: AxiosResponse<LogoutUserResponse>) => LogoutUserActionSuccess;
    FAILURE: (error: AxiosError) => LogoutUserActionFailure;
  };
}

export interface LogoutUserActionSuccess extends ApiSuccessAction {
  type: UserActionTypes.LOGOUT_USER__SUCCESS;
  payload: AxiosResponse<LogoutUserResponse>;
}

export interface LogoutUserActionFailure extends ApiFailureAction {
  type: UserActionTypes.LOGOUT_USER__FAILURE;
}
//</editor-fold>

export interface UserNotAuthorizedAction extends AnyAction {
  type: UserActionTypes.USER_NOT_AUTHORIZED;
}

//<editor-fold desc="Export action typings">
export type UserActions =
  | FetchUserInfoActionStart
  | FetchUserInfoActionSuccess
  | FetchUserInfoActionFailure
  | LoginUserActionStart
  | LoginUserActionSuccess
  | LoginUserActionFailure
  | LogoutUserActionStart
  | LogoutUserActionSuccess
  | LogoutUserActionFailure
  | UserNotAuthorizedAction;
//</editor-fold>
