import { connect } from 'react-redux';

import { RootState } from 'store';
import { challengesActions, selectFetchingChallengesStatus } from 'store/reducers/challenges';

import { HomePage as Component } from './view';

export const mapStateToProps = (state: RootState) => ({
  isFetchingChallenges: selectFetchingChallengesStatus(state),
  challenges: state.challenges.list,
});

export const mapActionsToProps = {
  fetchChallenges: challengesActions.fetchChallengesStart,
};

export const HomePage = connect(mapStateToProps, mapActionsToProps)(Component);
