import { AxiosPromise } from 'axios';

import { Axios, AxiosService } from 'services';
import { environment } from 'variables';

import { FetchUserInfoResponse, LoginUserResponse, LogoutUserResponse } from './types';

class UserControllerClass {
  constructor(private APIService: AxiosService) {}

  fetchUserInfo = (): AxiosPromise<FetchUserInfoResponse> => {
    return this.APIService.get('user');
  };

  loginUser = (code: string): AxiosPromise<LoginUserResponse> => {
    return this.APIService.post('discord', {
      code,
      redirect: `${environment.applicationURL}/discord`,
    });
  };

  logoutUser = (): AxiosPromise<LogoutUserResponse> => {
    return this.APIService.post('signout', {});
  };
}

export const UserController = new UserControllerClass(Axios);
