import { RootState } from 'store';
import { selectRequestStatus } from 'store/reducers/api-requests';
import { UserActionTypes } from 'store/reducers/user';

export const selectApplicationIsLoading = (state: RootState): boolean => {
  return (
    state.user.userInfo === undefined ||
    selectRequestStatus(state, UserActionTypes.FETCH_USER_INFO__START) ||
    selectRequestStatus(state, UserActionTypes.LOGOUT_USER__START)
  );
};
