import React from 'react';
import { Route, Router as ReactRouter, Switch } from 'react-router-dom';

import * as Pages from 'pages';
import { Navigation } from 'services';
import { Header } from 'components';

import { ROUTES } from './constants';

export const Router = () => (
  <ReactRouter history={Navigation.history}>
    <Switch>
      <Route exact path={ROUTES.System.Discord} component={Pages.DiscordAuthCallbackPage} />

      <Route path="/">
        <Header />

        <Switch>
          <Route exact path={ROUTES.Public.Home} component={Pages.HomePage} />

          <Pages.PageNotFound />
        </Switch>
      </Route>
    </Switch>
  </ReactRouter>
);
