import React from 'react';

import { Navigation } from 'services';
import { ROUTES } from 'router';
import { PageNotFound } from 'pages';
import { LogoSpinner } from 'components';

import { Props } from './types';

export class DiscordAuthCallbackPage extends React.Component<Props> {
  urlSearchParams?: URLSearchParams;

  get urlParams(): URLSearchParams {
    if (!this.urlSearchParams) {
      this.urlSearchParams = new URLSearchParams(this.props.location.search);
    }

    return this.urlSearchParams;
  }

  get accessGranted(): boolean {
    const discordAuthCode = this.urlParams.get('code');
    return !!discordAuthCode && discordAuthCode.length > 0;
  }

  get accessDenied(): boolean {
    const discordError = this.urlParams.get('error');
    return !!discordError && discordError === 'access_denied';
  }

  // Component lifecycle methods

  componentDidMount() {
    if (this.accessGranted) {
      this.props.loginUserWithDiscord(this.urlParams.get('code') as string);
      return;
    }

    if (this.accessDenied) {
      Navigation.goTo(ROUTES.Public.Home);
      return;
    }
  }

  // RENDER

  render() {
    if (this.urlParams.has('code') || this.urlParams.get('error') === 'access_denied') {
      return <LogoSpinner />;
    }

    return <PageNotFound />;
  }
}
