import { AxiosError, AxiosPromise, AxiosResponse } from 'axios';

import {
  FetchUserInfoResponse,
  LoginUserResponse,
  LogoutUserResponse,
  UserController,
} from 'controllers';

import * as Types from './types';

//<editor-fold desc="Fetch user info">
const fetchUserInfoStart = (): Types.FetchUserInfoActionStart => ({
  type: Types.UserActionTypes.FETCH_USER_INFO__START,
  apiRequest: (): AxiosPromise<FetchUserInfoResponse> => UserController.fetchUserInfo(),
  followupActions: { SUCCESS: fetchUserInfoSuccess, FAILURE: fetchUserInfoFailure },
});

const fetchUserInfoSuccess = (
  response: AxiosResponse<FetchUserInfoResponse>,
): Types.FetchUserInfoActionSuccess => ({
  type: Types.UserActionTypes.FETCH_USER_INFO__SUCCESS,
  payload: response,
});

const fetchUserInfoFailure = (error: AxiosError): Types.FetchUserInfoActionFailure => ({
  type: Types.UserActionTypes.FETCH_USER_INFO__FAILURE,
  error,
});
//</editor-fold>

//<editor-fold desc="Login user">
const loginUserStart = (discordCode: string): Types.LoginUserActionStart => ({
  type: Types.UserActionTypes.LOGIN_USER__START,
  discordCode,
});

const loginUserSuccess = (
  response: AxiosResponse<LoginUserResponse>,
): Types.LoginUserActionSuccess => ({
  type: Types.UserActionTypes.LOGIN_USER__SUCCESS,
  payload: response,
});

const loginUserFailure = (error: AxiosError): Types.LoginUserActionFailure => ({
  type: Types.UserActionTypes.LOGIN_USER__FAILURE,
  error,
});
//</editor-fold>

//<editor-fold desc="Logout user">
const logoutUserStart = (): Types.LogoutUserActionStart => ({
  type: Types.UserActionTypes.LOGOUT_USER__START,
  apiRequest: (): AxiosPromise<LogoutUserResponse> => UserController.logoutUser(),
  followupActions: { SUCCESS: logoutUserSuccess, FAILURE: logoutUserFailure },
});

const logoutUserSuccess = (
  response: AxiosResponse<LogoutUserResponse>,
): Types.LogoutUserActionSuccess => ({
  type: Types.UserActionTypes.LOGOUT_USER__SUCCESS,
  payload: response,
});

const logoutUserFailure = (error: AxiosError): Types.LogoutUserActionFailure => ({
  type: Types.UserActionTypes.LOGOUT_USER__FAILURE,
  error,
});
//</editor-fold>

const userNotAuthorized = (): Types.UserNotAuthorizedAction => ({
  type: Types.UserActionTypes.USER_NOT_AUTHORIZED,
});

export const actions = {
  fetchUserInfoStart,
  fetchUserInfoSuccess,
  fetchUserInfoFailure,
  loginUserStart,
  loginUserSuccess,
  loginUserFailure,
  logoutUserStart,
  logoutUserSuccess,
  logoutUserFailure,
  userNotAuthorized,
};
