import { AxiosPromise } from 'axios';
import { Axios, AxiosService } from 'services';

import { FetchChallengesResponse } from './types';

class ChallengeControllerClass {
  constructor(private APIService: AxiosService) {}

  fetchChallenges = (): AxiosPromise<FetchChallengesResponse> => {
    return this.APIService.get('pac/challenges');
  };
}

export const ChallengeController = new ChallengeControllerClass(Axios);
