import { RootAction } from 'store';

import { UserActionTypes, UserState as State } from './types';

const initialState: State = {
  userInfo: undefined,
};

export const userReducer = (state: State = initialState, action: RootAction): State => {
  switch (action.type) {
    case UserActionTypes.USER_NOT_AUTHORIZED:
      return { ...initialState, userInfo: null };

    case UserActionTypes.FETCH_USER_INFO__SUCCESS:
      return { ...state, userInfo: action.payload.data.user || null };

    case UserActionTypes.FETCH_USER_INFO__FAILURE:
      return { ...state, userInfo: null };

    case UserActionTypes.LOGIN_USER__SUCCESS:
      return { ...state, userInfo: action.payload.data };

    case UserActionTypes.LOGOUT_USER__SUCCESS:
      return { ...initialState, userInfo: null };

    default:
      return state;
  }
};
