import { RootState } from 'store';
import { selectRequestStatus } from 'store/reducers/api-requests';

import { ChallengesActionTypes } from './types';

export const selectFetchingChallengesStatus = (state: RootState): boolean => {
  return (
    selectRequestStatus(state, ChallengesActionTypes.FETCH_CHALLENGES_START) ||
    state.challenges.list === undefined
  );
};
