import React from 'react';

import { Router } from 'router';
import { LogoSpinner } from 'components';
import { UnexpectedErrorPage } from 'pages';
import 'styles/index.scss';

import { Props, State } from './types';

export class RootModule extends React.Component<Props, State> {
  state: State = {
    someErrorWasCatch: false,
  };

  // Lifecycle methods

  static getDerivedStateFromError(): State {
    return { someErrorWasCatch: true };
  }

  componentDidMount() {
    this.props.fetchUserData();
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error(error, errorInfo);
  }

  // RENDER

  render() {
    const { unexpectedError, isApplicationLoading } = this.props;
    const { someErrorWasCatch } = this.state;

    if (someErrorWasCatch || unexpectedError) {
      return <UnexpectedErrorPage />;
    }

    if (isApplicationLoading) {
      return <LogoSpinner />;
    }

    return <Router />;
  }
}
