import { AxiosError, AxiosPromise, AxiosResponse } from 'axios';

import { ChallengeController, FetchChallengesResponse } from 'controllers';

import * as Types from './types';

//<editor-fold desc="Fetch challenges">
const fetchChallengesStart = (): Types.FetchChallengesActionStart => ({
  type: Types.ChallengesActionTypes.FETCH_CHALLENGES_START,
  apiRequest: (): AxiosPromise<FetchChallengesResponse> => ChallengeController.fetchChallenges(),
  followupActions: { SUCCESS: fetchChallengesSuccess, FAILURE: fetchChallengesFailure },
});

const fetchChallengesSuccess = (
  response: AxiosResponse<FetchChallengesResponse>,
): Types.FetchChallengesActionSuccess => ({
  type: Types.ChallengesActionTypes.FETCH_CHALLENGES_SUCCESS,
  payload: response,
});

const fetchChallengesFailure = (error: AxiosError): Types.FetchChallengesActionFailure => ({
  type: Types.ChallengesActionTypes.FETCH_CHALLENGES_FAILURE,
  error,
});
//</editor-fold>

export const actions = {
  fetchChallengesStart,
  fetchChallengesSuccess,
  fetchChallengesFailure,
};
